mapper.select:
SELECT IF( COUNT(1), 'N', 'Y' ) AS checkYn
  FROM LETTNPROGRMLIST
 WHERE PROGRM_FILE_NM = #{progrmFileNm}

mapper.insert:
INSERT INTO LETTNPROGRMLIST ( PROGRM_FILE_NM
                            , PROGRM_STRE_PATH
                            , PROGRM_KOREAN_NM
                            , PROGRM_DC
                            , URL
                   ) VALUES ( #{progrmFileNm}
                            , #{progrmStrePath}
                            , #{progrmKoreanNm}
                            , #{progrmDc}
                            , #{url}
                            );

mapper.update:
UPDATE LETTNPROGRMLIST
   SET PROGRM_FILE_NM    = #{progrmFileNm}
     , PROGRM_STRE_PATH  = #{progrmStrePath}
     , PROGRM_KOREAN_NM  = #{progrmKoreanNm}
     , PROGRM_DC         = #{progrmDc}
     , URL               = #{url}
 WHERE PROGRM_FILE_NM = #{progrmFileNm}
